/* generated by scc from matmul.ss —— 着色器资源（勿手改） */
#ifndef SC_SHADER_MATMUL_H
#define SC_SHADER_MATMUL_H

#include <stddef.h>
#include <string.h>

#ifndef SC_SHADER_BLOB_DEFINED
#define SC_SHADER_BLOB_DEFINED
typedef struct sc_shader_blob {
    const char* entry;    /* 入口名（.ss 阶段函数名；反射条目 = 源 stem） */
    const char* stage;    /* "vert"/"frag"/"comp"；反射条目 = "" */
    const char* target;   /* 目标 tag："metal20000"/"glcore410"/... */
    const char* ext;      /* "metal"/"vert"/"spv"/"reflect.json" */
    const unsigned char* data;  /* 文本含结尾 NUL（可当 C 字符串） */
    size_t size;                /* 字节数（文本不含结尾 NUL） */
} sc_shader_blob;
#endif

typedef enum {
    SC_SHADER_MATMUL_MATMUL_VULKAN450_REFLECT = 0,
    SC_SHADER_MATMUL_MM_TILED_VULKAN450_SPV = 1,
    SC_SHADER_MATMUL_MATMUL_METAL20000_REFLECT = 2,
    SC_SHADER_MATMUL_MM_TILED_METAL20000 = 3,
    SC_SHADER_MATMUL_MATMUL_GLES310_REFLECT = 4,
    SC_SHADER_MATMUL_MM_TILED_GLES310 = 5,
    SC_SHADER_MATMUL_COUNT = 6
} sc_shader_matmul_id;

extern const sc_shader_blob sc_shader_matmul[SC_SHADER_MATMUL_COUNT];

/* 按下标取条目（非 inline，供 FFI/动态语言绑定；越界返回 NULL） */
const sc_shader_blob* sc_shader_matmul_get(size_t i);

/* 按 (entry, target) 查产物；entry 传源 stem、ext 传 "reflect.json" 查反射。
   target 可传 NULL = 单目标/任意目标首个命中。 */
static inline const sc_shader_blob* sc_shader_matmul_find(const char* entry, const char* target, const char* ext) {
    for (size_t i = 0; i < SC_SHADER_MATMUL_COUNT; i++) {
        const sc_shader_blob* b = &sc_shader_matmul[i];
        if (entry && strcmp(b->entry, entry) != 0) continue;
        if (target && strcmp(b->target, target) != 0) continue;
        if (ext && strcmp(b->ext, ext) != 0) continue;
        return b;
    }
    return 0;
}

#endif /* SC_SHADER_MATMUL_H */
